import outlines
from outlines import prompts

# no filter registered yet -> should fail
try:
    @outlines.prompt
    def greet(name):
        '{{ name | shout }}'
    greet('world')
    print('unexpected: succeeded without registration')
except Exception as e:
    print('OK: fails without registration ->', type(e).__name__)

prompts.register_filter('shout', str.upper)

@outlines.prompt
def greet2(name):
    '{{ name | shout }}'

print('after register:', greet2('world'))

prompts.unregister_filter('shout')

try:
    @outlines.prompt
    def greet3(name):
        '{{ name | shout }}'
    greet3('world')
    print('unexpected: succeeded after unregister')
except Exception as e:
    print('OK: new template fails after unregister ->', type(e).__name__)
